// src/pages/AdminUsers.js
import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { api } from '../utils/api';
import '../components/UI.css';

const DEPARTMENTS = ['laadpalen', 'zonnepanelen', 'algemeen', 'all'];
const DEPT_LABELS = { laadpalen: 'Laadpalen', zonnepanelen: 'Zonnepanelen', algemeen: 'Algemeen', all: 'Alle afdelingen' };

const emptyForm = { username: '', password: '', name: '', role: 'technician', department: 'laadpalen', active: true };

export default function AdminUsers() {
  const { token } = useAuth();
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState(emptyForm);
  const [editId, setEditId] = useState(null);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [saving, setSaving] = useState(false);

  const load = () => api.getUsers(token).then(d => setUsers(d.users)).finally(() => setLoading(false));
  useEffect(() => { load(); }, [token]);

  const openCreate = () => { setForm(emptyForm); setEditId(null); setShowForm(true); setError(''); };
  const openEdit = (u) => {
    setForm({ username: u.username, password: '', name: u.name, role: u.role, department: u.department, active: u.active });
    setEditId(u.id); setShowForm(true); setError('');
  };

  const handleSave = async () => {
    setSaving(true); setError('');
    try {
      if (editId) {
        const payload = { id: editId, name: form.name, role: form.role, department: form.department, active: form.active };
        if (form.password) payload.password = form.password;
        await api.updateUser(token, payload);
        setSuccess('Gebruiker bijgewerkt.');
      } else {
        await api.createUser(token, form);
        setSuccess('Gebruiker aangemaakt.');
      }
      await load(); setShowForm(false);
    } catch (e) { setError(e.message); }
    finally { setSaving(false); }
  };

  const handleDelete = async (id, name) => {
    if (!window.confirm(`Gebruiker "${name}" verwijderen?`)) return;
    try { await api.deleteUser(token, id); await load(); setSuccess('Verwijderd.'); }
    catch (e) { setError(e.message); }
  };

  if (loading) return <div style={{ display: 'flex', justifyContent: 'center', padding: 60 }}><span className="spinner" style={{ width: 28, height: 28 }} /></div>;

  return (
    <div className="fade-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <span style={{ color: 'var(--text2)', fontSize: 14 }}>{users.length} gebruikers</span>
        <button className="btn btn-primary btn-sm" onClick={openCreate}>+ Nieuwe gebruiker</button>
      </div>

      {success && <div className="alert alert-success" style={{ marginBottom: 16 }}><span>✓</span> {success}</div>}
      {error && !showForm && <div className="alert alert-error" style={{ marginBottom: 16 }}><span>⚠</span> {error}</div>}

      <div className="card" style={{ padding: 0, overflow: 'hidden' }}>
        <table className="table">
          <thead>
            <tr><th>Naam</th><th>Gebruikersnaam</th><th>Afdeling</th><th>Rol</th><th>Status</th><th></th></tr>
          </thead>
          <tbody>
            {users.map(u => (
              <tr key={u.id}>
                <td style={{ color: 'var(--text)', fontWeight: 500 }}>{u.name}</td>
                <td style={{ fontFamily: 'var(--font-display)', fontSize: 13 }}>{u.username}</td>
                <td><span className={`badge badge-dept-${u.department}`}>{DEPT_LABELS[u.department] || u.department}</span></td>
                <td><span className={`badge badge-role-${u.role}`}>{u.role === 'admin' ? 'Beheerder' : 'Technieker'}</span></td>
                <td><span style={{ fontSize: 12, color: u.active ? 'var(--success)' : 'var(--error)' }}>{u.active ? '● Actief' : '● Inactief'}</span></td>
                <td>
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button className="btn btn-ghost btn-sm" onClick={() => openEdit(u)}>Bewerken</button>
                    <button className="btn btn-danger btn-sm" onClick={() => handleDelete(u.id, u.name)}>✕</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showForm && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setShowForm(false)}>
          <div className="modal">
            <div className="modal-title">{editId ? 'Gebruiker bewerken' : 'Nieuwe gebruiker'}</div>
            {error && <div className="alert alert-error" style={{ marginBottom: 16 }}><span>⚠</span> {error}</div>}
            <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
              <div className="form-field">
                <label className="form-label">Volledige naam</label>
                <input className="form-input" value={form.name} onChange={e => setForm(f => ({...f, name: e.target.value}))} />
              </div>
              {!editId && (
                <div className="form-field">
                  <label className="form-label">Gebruikersnaam</label>
                  <input className="form-input" value={form.username} onChange={e => setForm(f => ({...f, username: e.target.value}))} />
                </div>
              )}
              <div className="form-field">
                <label className="form-label">{editId ? 'Nieuw wachtwoord (leeglaten = ongewijzigd)' : 'Wachtwoord'}</label>
                <input className="form-input" type="password" value={form.password} onChange={e => setForm(f => ({...f, password: e.target.value}))} />
              </div>
              <div className="form-field">
                <label className="form-label">Afdeling</label>
                <select className="form-input form-select" value={form.department} onChange={e => setForm(f => ({...f, department: e.target.value}))}>
                  {DEPARTMENTS.map(d => <option key={d} value={d}>{DEPT_LABELS[d]}</option>)}
                </select>
              </div>
              <div className="form-field">
                <label className="form-label">Rol</label>
                <select className="form-input form-select" value={form.role} onChange={e => setForm(f => ({...f, role: e.target.value}))}>
                  <option value="technician">Technieker</option>
                  <option value="admin">Beheerder</option>
                </select>
              </div>
              {editId && (
                <div className="form-field">
                  <label className="form-label">Status</label>
                  <select className="form-input form-select" value={form.active ? 'true' : 'false'} onChange={e => setForm(f => ({...f, active: e.target.value === 'true'}))}>
                    <option value="true">Actief</option>
                    <option value="false">Inactief</option>
                  </select>
                </div>
              )}
              <div style={{ display: 'flex', gap: 10, marginTop: 8 }}>
                <button className="btn btn-primary" onClick={handleSave} disabled={saving} style={{ flex: 1, justifyContent: 'center' }}>
                  {saving ? 'Opslaan...' : 'Opslaan'}
                </button>
                <button className="btn btn-ghost" onClick={() => setShowForm(false)}>Annuleren</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
